SELECT r.id, r.name, r.days, r.price, r.create_time AS createTime, u.nickname AS userNickname FROM route r LEFT JOIN system_users u ON r.creator = u.id WHERE r.deleted = 0
AND r.name LIKE CONCAT('%', #{reqVO.name}, '%')
AND r.creator = #{reqVO.userId}
AND r.days BETWEEN #{reqVO.days[0]} AND #{reqVO.days[1]}
AND r.price BETWEEN #{reqVO.price[0]} AND #{reqVO.price[1]}
AND u.nickname LIKE CONCAT('%', #{reqVO.userNickName}, '%')
AND r.create_time BETWEEN #{reqVO.createTime[0]} AND #{reqVO.createTime[1]}
ORDER BY r.create_time DESC

